TriggerOraclev10g.body:
DECLARE envbq_status number; valor_envbq_update number; vro_error tkr_errores%ROWTYPE; BEGIN -- Caso INSERT IF INSERTING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_USUARIOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_USUARIOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_USUARIOS ( ENVIO_BQ, ID, FECHA_NACIMIENTO, ID_CIUDAD_RESIDENCIA, DIRECCION, CORREO_ELECTRONICO, ID_USUARIO_CREACION, FECHA_CREACION, ESTADO, MEDICO_CABECERA, CORREO_MEDICO_CABECERA, ID_PRESTADOR_SALUD, ASEGURADOR_2, ID_ESTADO_USUARIO, ID_GENERO, ID_BARRIO, DISPONIBLE, AUTORIZACION_MEDICO, LUGAR_PRACTICA, ID_ROL, ID_TIPO_IDENTIFICACION, IDENTIFICACION, CEDULA_PROFESIONAL, DESCRIPCION, OTRO_BARRIO, ID_PERFIL_DOCTOR, OTRA_CIUDAD, ID_USUARIO_ACTIVA, FECHA_ACTIVACION, ID_CODIGO_TARIFA, TIPO_TARIFA, ID_REGIMEN_ASEGURAMIENTO, FECHA_DISPONIBLE, ID_MEDIO, OTRO_MEDIO, FLAG_FOTO, CODIGO_CAMBIO_CLAVE, DURACION_MINUTOS_CITA, TRABAJA_FESTIVOS, LINEA_SERVICIO, BLOQUEADO, LINEAS_SERVICIO, ID_ACTIVECAMPAIGN, IDIOMAS, DETALLE_DIRECCION, CODIGO_REFERENCIA, ID_REFERENCIADO_POR, REGIMEN_SIMPLE, SALDO_REFERENCIAS, ID_REFERIDO_POR, ETIQUETA_FIRMA, CODIGO_AUTORIZACION, EXCLUIR_ENCUESTAS, ID_PAIS, ID_PLAN_ASEGURADOR, BARRIO, ZONA, SISBEN, ETNIA, NOMBRES, APELLIDOS ) VALUES ( 0, -- ENVIO_BQ para INSERT :NEW.ID, :NEW.FECHA_NACIMIENTO, :NEW.ID_CIUDAD_RESIDENCIA, :NEW.DIRECCION, :NEW.CORREO_ELECTRONICO, :NEW.ID_USUARIO_CREACION, :NEW.FECHA_CREACION, :NEW.ESTADO, :NEW.MEDICO_CABECERA, :NEW.CORREO_MEDICO_CABECERA, :NEW.ID_PRESTADOR_SALUD, :NEW.ASEGURADOR_2, :NEW.ID_ESTADO_USUARIO, :NEW.ID_GENERO, :NEW.ID_BARRIO, :NEW.DISPONIBLE, :NEW.AUTORIZACION_MEDICO, :NEW.LUGAR_PRACTICA, :NEW.ID_ROL, :NEW.ID_TIPO_IDENTIFICACION, :NEW.IDENTIFICACION, :NEW.CEDULA_PROFESIONAL, :NEW.DESCRIPCION, :NEW.OTRO_BARRIO, :NEW.ID_PERFIL_DOCTOR, :NEW.OTRA_CIUDAD, :NEW.ID_USUARIO_ACTIVA, :NEW.FECHA_ACTIVACION, :NEW.ID_CODIGO_TARIFA, :NEW.TIPO_TARIFA, :NEW.ID_REGIMEN_ASEGURAMIENTO, :NEW.FECHA_DISPONIBLE, :NEW.ID_MEDIO, :NEW.OTRO_MEDIO, :NEW.FLAG_FOTO, :NEW.CODIGO_CAMBIO_CLAVE, :NEW.DURACION_MINUTOS_CITA, :NEW.TRABAJA_FESTIVOS, :NEW.LINEA_SERVICIO, :NEW.BLOQUEADO, :NEW.LINEAS_SERVICIO, :NEW.ID_ACTIVECAMPAIGN, :NEW.IDIOMAS, :NEW.DETALLE_DIRECCION, :NEW.CODIGO_REFERENCIA, :NEW.ID_REFERENCIADO_POR, :NEW.REGIMEN_SIMPLE, :NEW.SALDO_REFERENCIAS, :NEW.ID_REFERIDO_POR, :NEW.ETIQUETA_FIRMA, :NEW.CODIGO_AUTORIZACION, :NEW.EXCLUIR_ENCUESTAS, :NEW.ID_PAIS, :NEW.ID_PLAN_ASEGURADOR, :NEW.BARRIO, :NEW.ZONA, :NEW.SISBEN, :NEW.ETNIA, :NEW.NOMBRES, :NEW.APELLIDOS ); END IF;
-- Caso UPDATE IF UPDATING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_USUARIOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NULL THEN
INSERT INTO TKRBQ_USUARIOS ( ENVIO_BQ, ID, FECHA_NACIMIENTO, ID_CIUDAD_RESIDENCIA, DIRECCION, CORREO_ELECTRONICO, ID_USUARIO_CREACION, FECHA_CREACION, ESTADO, MEDICO_CABECERA, CORREO_MEDICO_CABECERA, ID_PRESTADOR_SALUD, ASEGURADOR_2, ID_ESTADO_USUARIO, ID_GENERO, ID_BARRIO, DISPONIBLE, AUTORIZACION_MEDICO, LUGAR_PRACTICA, ID_ROL, ID_TIPO_IDENTIFICACION, IDENTIFICACION, CEDULA_PROFESIONAL, DESCRIPCION, OTRO_BARRIO, ID_PERFIL_DOCTOR, OTRA_CIUDAD, ID_USUARIO_ACTIVA, FECHA_ACTIVACION, ID_CODIGO_TARIFA, TIPO_TARIFA, ID_REGIMEN_ASEGURAMIENTO, FECHA_DISPONIBLE, ID_MEDIO, OTRO_MEDIO, FLAG_FOTO, CODIGO_CAMBIO_CLAVE, DURACION_MINUTOS_CITA, TRABAJA_FESTIVOS, LINEA_SERVICIO, BLOQUEADO, LINEAS_SERVICIO, ID_ACTIVECAMPAIGN, IDIOMAS, DETALLE_DIRECCION, CODIGO_REFERENCIA, ID_REFERENCIADO_POR, REGIMEN_SIMPLE, SALDO_REFERENCIAS, ID_REFERIDO_POR, ETIQUETA_FIRMA, CODIGO_AUTORIZACION, EXCLUIR_ENCUESTAS, ID_PAIS, ID_PLAN_ASEGURADOR, BARRIO, ZONA, SISBEN, ETNIA, NOMBRES, APELLIDOS ) VALUES ( 2, -- ENVIO_BQ para INSERT :NEW.ID, :NEW.FECHA_NACIMIENTO, :NEW.ID_CIUDAD_RESIDENCIA, :NEW.DIRECCION, :NEW.CORREO_ELECTRONICO, :NEW.ID_USUARIO_CREACION, :NEW.FECHA_CREACION, :NEW.ESTADO, :NEW.MEDICO_CABECERA, :NEW.CORREO_MEDICO_CABECERA, :NEW.ID_PRESTADOR_SALUD, :NEW.ASEGURADOR_2, :NEW.ID_ESTADO_USUARIO, :NEW.ID_GENERO, :NEW.ID_BARRIO, :NEW.DISPONIBLE, :NEW.AUTORIZACION_MEDICO, :NEW.LUGAR_PRACTICA, :NEW.ID_ROL, :NEW.ID_TIPO_IDENTIFICACION, :NEW.IDENTIFICACION, :NEW.CEDULA_PROFESIONAL, :NEW.DESCRIPCION, :NEW.OTRO_BARRIO, :NEW.ID_PERFIL_DOCTOR, :NEW.OTRA_CIUDAD, :NEW.ID_USUARIO_ACTIVA, :NEW.FECHA_ACTIVACION, :NEW.ID_CODIGO_TARIFA, :NEW.TIPO_TARIFA, :NEW.ID_REGIMEN_ASEGURAMIENTO, :NEW.FECHA_DISPONIBLE, :NEW.ID_MEDIO, :NEW.OTRO_MEDIO, :NEW.FLAG_FOTO, :NEW.CODIGO_CAMBIO_CLAVE, :NEW.DURACION_MINUTOS_CITA, :NEW.TRABAJA_FESTIVOS, :NEW.LINEA_SERVICIO, :NEW.BLOQUEADO, :NEW.LINEAS_SERVICIO, :NEW.ID_ACTIVECAMPAIGN, :NEW.IDIOMAS, :NEW.DETALLE_DIRECCION, :NEW.CODIGO_REFERENCIA, :NEW.ID_REFERENCIADO_POR, :NEW.REGIMEN_SIMPLE, :NEW.SALDO_REFERENCIAS, :NEW.ID_REFERIDO_POR, :NEW.ETIQUETA_FIRMA, :NEW.CODIGO_AUTORIZACION, :NEW.EXCLUIR_ENCUESTAS, :NEW.ID_PAIS, :NEW.ID_PLAN_ASEGURADOR, :NEW.BARRIO, :NEW.ZONA, :NEW.SISBEN, :NEW.ETNIA, :NEW.NOMBRES, :NEW.APELLIDOS );
ELSE IF envbq_status = 0 THEN valor_envbq_update := 0; ELSE valor_envbq_update := 2; END IF;
UPDATE TKRBQ_USUARIOS SET ENVIO_BQ = valor_envbq_update, ID = :NEW.ID, FECHA_NACIMIENTO = :NEW.FECHA_NACIMIENTO, ID_CIUDAD_RESIDENCIA = :NEW.ID_CIUDAD_RESIDENCIA, DIRECCION = :NEW.DIRECCION, CORREO_ELECTRONICO = :NEW.CORREO_ELECTRONICO, ID_USUARIO_CREACION = :NEW.ID_USUARIO_CREACION, FECHA_CREACION = :NEW.FECHA_CREACION, ESTADO = :NEW.ESTADO, MEDICO_CABECERA = :NEW.MEDICO_CABECERA, CORREO_MEDICO_CABECERA = :NEW.CORREO_MEDICO_CABECERA, ID_PRESTADOR_SALUD = :NEW.ID_PRESTADOR_SALUD, ASEGURADOR_2 = :NEW.ASEGURADOR_2, ID_ESTADO_USUARIO = :NEW.ID_ESTADO_USUARIO, ID_GENERO = :NEW.ID_GENERO, ID_BARRIO = :NEW.ID_BARRIO, DISPONIBLE = :NEW.DISPONIBLE, AUTORIZACION_MEDICO = :NEW.AUTORIZACION_MEDICO, LUGAR_PRACTICA = :NEW.LUGAR_PRACTICA, ID_ROL = :NEW.ID_ROL, ID_TIPO_IDENTIFICACION = :NEW.ID_TIPO_IDENTIFICACION, IDENTIFICACION = :NEW.IDENTIFICACION, CEDULA_PROFESIONAL = :NEW.CEDULA_PROFESIONAL, DESCRIPCION = :NEW.DESCRIPCION, OTRO_BARRIO = :NEW.OTRO_BARRIO, ID_PERFIL_DOCTOR = :NEW.ID_PERFIL_DOCTOR, OTRA_CIUDAD = :NEW.OTRA_CIUDAD, ID_USUARIO_ACTIVA = :NEW.ID_USUARIO_ACTIVA, FECHA_ACTIVACION = :NEW.FECHA_ACTIVACION, ID_CODIGO_TARIFA = :NEW.ID_CODIGO_TARIFA, TIPO_TARIFA = :NEW.TIPO_TARIFA, ID_REGIMEN_ASEGURAMIENTO = :NEW.ID_REGIMEN_ASEGURAMIENTO, FECHA_DISPONIBLE = :NEW.FECHA_DISPONIBLE, ID_MEDIO = :NEW.ID_MEDIO, OTRO_MEDIO = :NEW.OTRO_MEDIO, FLAG_FOTO = :NEW.FLAG_FOTO, CODIGO_CAMBIO_CLAVE = :NEW.CODIGO_CAMBIO_CLAVE, DURACION_MINUTOS_CITA = :NEW.DURACION_MINUTOS_CITA, TRABAJA_FESTIVOS = :NEW.TRABAJA_FESTIVOS, LINEA_SERVICIO = :NEW.LINEA_SERVICIO, BLOQUEADO = :NEW.BLOQUEADO, LINEAS_SERVICIO = :NEW.LINEAS_SERVICIO, ID_ACTIVECAMPAIGN = :NEW.ID_ACTIVECAMPAIGN, IDIOMAS = :NEW.IDIOMAS, DETALLE_DIRECCION = :NEW.DETALLE_DIRECCION, CODIGO_REFERENCIA = :NEW.CODIGO_REFERENCIA, ID_REFERENCIADO_POR = :NEW.ID_REFERENCIADO_POR, REGIMEN_SIMPLE = :NEW.REGIMEN_SIMPLE, SALDO_REFERENCIAS = :NEW.SALDO_REFERENCIAS, ID_REFERIDO_POR = :NEW.ID_REFERIDO_POR, ETIQUETA_FIRMA = :NEW.ETIQUETA_FIRMA, CODIGO_AUTORIZACION = :NEW.CODIGO_AUTORIZACION, EXCLUIR_ENCUESTAS = :NEW.EXCLUIR_ENCUESTAS, ID_PAIS = :NEW.ID_PAIS, ID_PLAN_ASEGURADOR = :NEW.ID_PLAN_ASEGURADOR, BARRIO = :NEW.BARRIO, ZONA = :NEW.ZONA, SISBEN = :NEW.SISBEN, ETNIA = :NEW.ETNIA, NOMBRES = :NEW.NOMBRES, APELLIDOS =:NEW.APELLIDOS
WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF; END IF;
-- Caso DELETE IF DELETING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_USUARIOS WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_USUARIOS WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_USUARIOS ( ENVIO_BQ, ID, FECHA_NACIMIENTO, ID_CIUDAD_RESIDENCIA, DIRECCION, CORREO_ELECTRONICO, ID_USUARIO_CREACION, FECHA_CREACION, ESTADO, MEDICO_CABECERA, CORREO_MEDICO_CABECERA, ID_PRESTADOR_SALUD, ASEGURADOR_2, ID_ESTADO_USUARIO, ID_GENERO, ID_BARRIO, DISPONIBLE, AUTORIZACION_MEDICO, LUGAR_PRACTICA, ID_ROL, ID_TIPO_IDENTIFICACION, IDENTIFICACION, CEDULA_PROFESIONAL, DESCRIPCION, OTRO_BARRIO, ID_PERFIL_DOCTOR, OTRA_CIUDAD, ID_USUARIO_ACTIVA, FECHA_ACTIVACION, ID_CODIGO_TARIFA, TIPO_TARIFA, ID_REGIMEN_ASEGURAMIENTO, FECHA_DISPONIBLE, ID_MEDIO, OTRO_MEDIO, FLAG_FOTO, CODIGO_CAMBIO_CLAVE, DURACION_MINUTOS_CITA, TRABAJA_FESTIVOS, LINEA_SERVICIO, BLOQUEADO, LINEAS_SERVICIO, ID_ACTIVECAMPAIGN, IDIOMAS, DETALLE_DIRECCION, CODIGO_REFERENCIA, ID_REFERENCIADO_POR, REGIMEN_SIMPLE, SALDO_REFERENCIAS, ID_REFERIDO_POR, ETIQUETA_FIRMA, CODIGO_AUTORIZACION, EXCLUIR_ENCUESTAS, ID_PAIS, ID_PLAN_ASEGURADOR, BARRIO, ZONA, SISBEN, ETNIA, NOMBRES, APELLIDOS ) VALUES ( -1, -- ENVIO_BQ para DELETE :OLD.ID, :OLD.FECHA_NACIMIENTO, :OLD.ID_CIUDAD_RESIDENCIA, :OLD.DIRECCION, :OLD.CORREO_ELECTRONICO, :OLD.ID_USUARIO_CREACION, :OLD.FECHA_CREACION, :OLD.ESTADO, :OLD.MEDICO_CABECERA, :OLD.CORREO_MEDICO_CABECERA, :OLD.ID_PRESTADOR_SALUD, :OLD.ASEGURADOR_2, :OLD.ID_ESTADO_USUARIO, :OLD.ID_GENERO, :OLD.ID_BARRIO, :OLD.DISPONIBLE, :OLD.AUTORIZACION_MEDICO, :OLD.LUGAR_PRACTICA, :OLD.ID_ROL, :OLD.ID_TIPO_IDENTIFICACION, :OLD.IDENTIFICACION, :OLD.CEDULA_PROFESIONAL, :OLD.DESCRIPCION, :OLD.OTRO_BARRIO, :OLD.ID_PERFIL_DOCTOR, :OLD.OTRA_CIUDAD, :OLD.ID_USUARIO_ACTIVA, :OLD.FECHA_ACTIVACION, :OLD.ID_CODIGO_TARIFA, :OLD.TIPO_TARIFA, :OLD.ID_REGIMEN_ASEGURAMIENTO, :OLD.FECHA_DISPONIBLE, :OLD.ID_MEDIO, :OLD.OTRO_MEDIO, :OLD.FLAG_FOTO, :OLD.CODIGO_CAMBIO_CLAVE, :OLD.DURACION_MINUTOS_CITA, :OLD.TRABAJA_FESTIVOS, :OLD.LINEA_SERVICIO, :OLD.BLOQUEADO, :OLD.LINEAS_SERVICIO, :OLD.ID_ACTIVECAMPAIGN, :OLD.IDIOMAS, :OLD.DETALLE_DIRECCION, :OLD.CODIGO_REFERENCIA, :OLD.ID_REFERENCIADO_POR, :OLD.REGIMEN_SIMPLE, :OLD.SALDO_REFERENCIAS, :OLD.ID_REFERIDO_POR, :OLD.ETIQUETA_FIRMA, :OLD.CODIGO_AUTORIZACION, :OLD.EXCLUIR_ENCUESTAS, :OLD.ID_PAIS, :OLD.ID_PLAN_ASEGURADOR, :OLD.BARRIO, :OLD.ZONA, :OLD.SISBEN, :OLD.ETNIA, :OLD.NOMBRES, :OLD.APELLIDOS ); END IF;
EXCEPTION WHEN OTHERS THEN vro_error.nombre_programa := 'TRG_SYNC_TKR_USUARIOS'; vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ'; vro_error.parametros := 'id de consultas: '||:old.id; uti_ge_excepciones_pkg.p_grabar_log (vro_error);
END;
